import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload, UserPlus } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminArtistForm = () => {
  const { id } = useParams(); // Detects if we are editing
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState<File | null>(null);

  // Manual Input State
  const [formData, setFormData] = useState({
    Artist_ID: '',
    Name_En: '',
    Name_Ar: '',
    Bio_En: '',
    Image: ''
  });

  // Logic: If ID exists, fetch existing data for Editing
  useEffect(() => {
    if (id) {
      AdminService.getArtistById(id).then((res: any) => {
        setFormData(res.data);
      });
    }
  }, [id]);

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertArtist(formData);
      toast.success(id ? "Artist Updated" : "Artist Created");
      navigate('/admin/artists');
    } catch (err) {
      toast.error("Operation Failed");
    } finally {
      setLoading(false);
    }
  };

  const handleExcelImport = async () => {
    if (!file) return toast.error("Select Excel file first");
    setLoading(true);
    try {
      await AdminService.importData('artist', file);
      toast.success("Bulk Import Success");
      navigate('/admin/artists');
    } catch (err) {
      toast.error("Excel Import Failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto p-8 space-y-10">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 font-bold text-[10px] uppercase tracking-widest hover:text-primary">
        <ArrowLeft size={14} /> Back
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        {/* Left: Manual Form */}
        <div className="lg:col-span-2 bg-[#0f0f0f] p-10 rounded-[2.5rem] border border-white/5">
          <h2 className="text-2xl font-black italic uppercase mb-8">{id ? 'Edit' : 'Manual'} <span className="text-primary">Artist</span></h2>
          <form onSubmit={handleManualSubmit} className="grid grid-cols-2 gap-6">
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Unique ID</label>
              <input value={formData.Artist_ID} onChange={e => setFormData({...formData, Artist_ID: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl outline-none focus:border-primary text-white" placeholder="e.g. AR-01" required />
            </div>
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Name (English)</label>
              <input value={formData.Name_En} onChange={e => setFormData({...formData, Name_En: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl outline-none focus:border-primary text-white" placeholder="John Doe" required />
            </div>
            <div className="col-span-2 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-500 ml-2">Biography</label>
              <textarea value={formData.Bio_En} onChange={e => setFormData({...formData, Bio_En: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl h-32 outline-none focus:border-primary text-white" placeholder="Write artist history here..." />
            </div>
            <button type="submit" disabled={loading} className="col-span-2 bg-primary text-black font-black uppercase py-4 rounded-xl hover:bg-yellow-500 transition-all flex items-center justify-center gap-2">
              <Save size={18} /> {id ? 'Save Changes' : 'Create Artist'}
            </button>
          </form>
        </div>

        {/* Right: Excel Option (Only show during "Add") */}
        {!id && (
          <div className="bg-white/5 p-10 rounded-[2.5rem] border border-white/5 h-fit">
            <h2 className="text-lg font-black italic uppercase mb-6 text-gray-400">Bulk <span className="text-white">Import</span></h2>
            <div className="border-2 border-dashed border-white/10 rounded-2xl p-6 text-center space-y-4">
              <input type="file" className="hidden" id="excel" onChange={e => setFile(e.target.files?.[0] || null)} />
              <label htmlFor="excel" className="cursor-pointer block">
                <Upload className="mx-auto text-primary mb-2" size={32} />
                <p className="text-[10px] font-bold text-gray-500">{file ? file.name : 'Select File'}</p>
              </label>
              <button onClick={handleExcelImport} className="w-full bg-white text-black py-3 rounded-xl font-black text-[10px] uppercase tracking-widest">Process</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};
